int segA = 2;
int segB = 3;
int segC = 4;
int segD = 5;
int segE = 6;
int segF = 7;
int segG = 8;
int btnPin = 9;

int counter = 0;
int lastBtnState = HIGH;

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);
  pinMode(btnPin, INPUT_PULLUP);
  displayDigit(0);
}

void loop() {
  int btnState = digitalRead(btnPin);

  if (btnState == LOW && lastBtnState == HIGH) {
    counter++;
    if (counter > 9) {
      counter = 0;
    }
    displayDigit(counter);
    delay(20);
  }
  lastBtnState = btnState;
  delay(10);
}

void displayDigit(int digit) {
  int a = 0, b = 0, c = 0, d = 0, e = 0, f = 0, g = 0;

  if (digit == 0) { a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 0; }
  else if (digit == 1) { a = 0; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0; }
  else if (digit == 2) { a = 1; b = 1; c = 0; d = 1; e = 1; f = 0; g = 1; }
  else if (digit == 3) { a = 1; b = 1; c = 1; d = 1; e = 0; f = 0; g = 1; }
  else if (digit == 4) { a = 0; b = 1; c = 1; d = 0; e = 0; f = 1; g = 1; }
  else if (digit == 5) { a = 1; b = 0; c = 1; d = 1; e = 0; f = 1; g = 1; }
  else if (digit == 6) { a = 1; b = 0; c = 1; d = 1; e = 1; f = 1; g = 1; }
  else if (digit == 7) { a = 1; b = 1; c = 1; d = 0; e = 0; f = 0; g = 0; }
  else if (digit == 8) { a = 1; b = 1; c = 1; d = 1; e = 1; f = 1; g = 1; }
  else if (digit == 9) { a = 1; b = 1; c = 1; d = 1; e = 0; f = 1; g = 1; }

  digitalWrite(segA, a);
  digitalWrite(segB, b);
  digitalWrite(segC, c);
  digitalWrite(segD, d);
  digitalWrite(segE, e);
  digitalWrite(segF, f);
  digitalWrite(segG, g);
}

